func CheckIBasicMatrixServiceService(ctx context.Context, sm binder.ServiceManager, name string) (IBasicMatrixService, error) {
	service, err := sm.CheckService(ctx, name)
	if err != nil {
		return nil, err
	}
	return NewIBasicMatrixServiceClient(service), nil
}

func WaitIBasicMatrixServiceService(ctx context.Context, sm binder.ServiceManager, name string) (IBasicMatrixService, error) {
	service, err := sm.WaitService(ctx, name)
	if err != nil {
		return nil, err
	}
	return NewIBasicMatrixServiceClient(service), nil
}

func AddIBasicMatrixServiceService(ctx context.Context, sm binder.ServiceManager, name string, impl IBasicMatrixService, opts ...binder.AddServiceOption) error {
	if registrar, ok := sm.(binder.LocalHandlerRegistrar); ok {
		return sm.AddService(ctx, name, NewIBasicMatrixServiceHandlerWithRegistrar(registrar, impl), opts...)
	}
	return sm.AddService(ctx, name, NewIBasicMatrixServiceHandler(impl), opts...)
}
